export const cinematicFlows = [actsAdministrativeFlow, padFlow, biddingFlow, civilLiabilityFlow, powersFlow, localOrganicFlow, municipalTaxFlow, municipalPoliceFlow];

export function findFlowById(flowId) {
  return cinematicFlows.find((flow) => flow.id === flowId) || cinematicFlows[0];
}

export function findStepById(id, flow = actsAdministrativeFlow) {
  return flow.steps.find((step) => step.id === id) || flow.steps[0];
}
